#!/usr/bin/env bash
set -Eeuo pipefail

REPO="${ROUTEIQ_REPO:-/tmp/routeiq-v13}"
EXPECTED_BRANCH="${ROUTEIQ_EXPECTED_BRANCH:-track1-v13-ultra-local}"
EXPECTED_BASE="${ROUTEIQ_EXPECTED_BASE:-4785920}"
BASE_IMAGE="${ROUTEIQ_BASE_IMAGE:-routeiq-v14-ultra-local:base}"
LOCAL_IMAGE="${ROUTEIQ_LOCAL_IMAGE:-routeiq-v14-ultra-local:test}"
PUBLISH="${ROUTEIQ_PUBLISH:-1}"

say() { printf '\n==> %s\n' "$*"; }
die() { printf '\nERROR: %s\n' "$*" >&2; exit 1; }
trap 'printf "\nFAILED at line %s. The 100%% / 3,791-token champion and portal submission were not touched.\n" "$LINENO" >&2' ERR

command -v git >/dev/null || die "git is required"
command -v python3 >/dev/null || die "python3 is required"
command -v docker >/dev/null || die "docker is required"
command -v timeout >/dev/null || die "GNU timeout is required"
[[ -d "$REPO" ]] || die "worktree not found: $REPO"
cd "$REPO"
[[ "$(git rev-parse --is-inside-work-tree 2>/dev/null)" == "true" ]] || die "$REPO is not a git worktree"
[[ "$(git branch --show-current)" == "$EXPECTED_BRANCH" ]] || die "expected branch $EXPECTED_BRANCH"
git cat-file -e "${EXPECTED_BASE}^{commit}" 2>/dev/null || die "protected champion commit $EXPECTED_BASE is unavailable"
git merge-base --is-ancestor "$EXPECTED_BASE" HEAD || die "branch is not descended from protected champion"
git diff --quiet || die "tracked working-tree changes exist; commit or stash them first"
git diff --cached --quiet || die "staged changes exist; commit or unstage them first"
docker info >/dev/null 2>&1 || die "Docker daemon is unavailable"

say "Installing isolated v1.4 candidate"
STAMP="$(date +%Y%m%d-%H%M%S)"
if [[ -e track1-v14-agent ]]; then
  tar -czf "/tmp/routeiq-v14-backup-${STAMP}.tgz" track1-v14-agent
  rm -rf track1-v14-agent
fi
PAYLOAD_FILE="$(mktemp)"
base64 -d > "$PAYLOAD_FILE" <<'ROUTEIQ_V14_PAYLOAD'

ROUTEIQ_V14_PAYLOAD
tar -xzf "$PAYLOAD_FILE" -C "$REPO"
rm -f "$PAYLOAD_FILE"

if [[ -n "$(git diff --name-only -- track1-v12-agent)" ]]; then
  die "protected champion folder was modified"
fi

say "Running Python unit and routing tests"
(
  cd track1-v14-agent
  python3 -m unittest discover -s tests -v
)

say "Building Qwen3-4B Q4 candidate image"
docker build --progress=plain --build-arg QWEN_MODE=thinking -t "$BASE_IMAGE" track1-v14-agent

BENCH_ROOTS=()
LAST_BENCH_ROOT=""
run_benchmark() {
  local mode="$1"
  local root
  root="$(mktemp -d)"
  BENCH_ROOTS+=("$root")
  LAST_BENCH_ROOT="$root"
  mkdir -p "$root/input" "$root/output"
  chmod 777 "$root/output"
  cp track1-v14-agent/bench/tasks.json "$root/input/tasks.json"

  say "Running 19-task local benchmark: mode=$mode, 2 CPU / 4 GB"
  local start end run_status score_status
  start="$(date +%s)"
  set +e
  timeout 540 docker run --rm \
    --network none \
    --cpus=2 \
    --memory=4g \
    -e ROUTEIQ_LOCAL_ONLY=1 \
    -e QWEN_MODE="$mode" \
    -v "$root/input:/input:ro" \
    -v "$root/output:/output" \
    "$BASE_IMAGE" 2>&1 | tee "$root/container.log"
  run_status="${PIPESTATUS[0]}"
  set -e
  end="$(date +%s)"
  printf '%s\n' "$((end - start))" > "$root/runtime.txt"

  if [[ "$run_status" -ne 0 || ! -s "$root/output/results.json" ]]; then
    printf 'Container failed for mode=%s; logs=%s\n' "$mode" "$root/container.log" >&2
    return 1
  fi

  set +e
  python3 track1-v14-agent/bench/score_benchmark.py \
    "$root/input/tasks.json" \
    "$root/output/results.json" \
    "$root/runtime.txt" | tee "$root/score.log"
  score_status="${PIPESTATUS[0]}"
  set -e
  return "$score_status"
}

CHOSEN_MODE=""
CHOSEN_ROOT=""
if run_benchmark thinking; then
  CHOSEN_MODE="thinking"
  CHOSEN_ROOT="$LAST_BENCH_ROOT"
else
  THINKING_ROOT="$LAST_BENCH_ROOT"
  say "Thinking mode missed the perfect gate; trying one deterministic non-thinking configuration"
  if run_benchmark nonthinking; then
    CHOSEN_MODE="nonthinking"
    CHOSEN_ROOT="$LAST_BENCH_ROOT"
  else
    NONTHINKING_ROOT="$LAST_BENCH_ROOT"
    printf '\nBoth guarded modes failed. No image was published and no portal change was made.\n' >&2
    printf 'Thinking report: %s/output/benchmark-report.json\n' "$THINKING_ROOT" >&2
    printf 'Non-thinking report: %s/output/benchmark-report.json\n' "$NONTHINKING_ROOT" >&2
    exit 1
  fi
fi

say "Perfect local gate passed with mode=$CHOSEN_MODE"
say "Embedding the selected mode into the final candidate image"
docker build --progress=plain --build-arg QWEN_MODE="$CHOSEN_MODE" -t "$LOCAL_IMAGE" track1-v14-agent

ARCH="$(docker image inspect --format '{{.Architecture}}' "$LOCAL_IMAGE")"
SIZE="$(docker image inspect --format '{{.Size}}' "$LOCAL_IMAGE")"
ENV_MODE="$(docker image inspect --format '{{range .Config.Env}}{{println .}}{{end}}' "$LOCAL_IMAGE" | grep '^QWEN_MODE=' | tail -n1 || true)"
[[ "$ARCH" == "amd64" ]] || die "candidate architecture is $ARCH, not amd64"
[[ "$SIZE" -lt 8000000000 ]] || die "candidate image is unexpectedly large: $SIZE bytes"
[[ "$ENV_MODE" == "QWEN_MODE=$CHOSEN_MODE" ]] || die "selected Qwen mode was not embedded"

say "Saving candidate code locally without pushing source"
find track1-v14-agent -type d -name __pycache__ -prune -exec rm -rf {} +
find track1-v14-agent -type f -name '*.pyc' -delete
git add track1-v14-agent
if ! git diff --cached --quiet; then
  git commit -m "feat(track1): add v1.4 four-billion-parameter ultra-local candidate"
fi
COMMIT="$(git rev-parse HEAD)"
REPORT="$CHOSEN_ROOT/output/benchmark-report.json"

if [[ "$PUBLISH" != "1" ]]; then
  say "Perfect benchmark passed; publication skipped by ROUTEIQ_PUBLISH=$PUBLISH"
  printf 'Candidate commit: %s\nBenchmark report: %s\nSelected mode: %s\n' "$COMMIT" "$REPORT" "$CHOSEN_MODE"
  exit 0
fi

command -v gh >/dev/null || die "GitHub CLI is required for candidate publication"
OWNER="$(gh repo view --json owner --jq '.owner.login')"
[[ -n "$OWNER" ]] || die "could not determine GitHub repository owner"
TOKEN="$(gh auth token)"
[[ -n "$TOKEN" ]] || die "GitHub CLI is not authenticated"
OPAQUE="$(python3 - <<'PYOPAQUE'
import secrets
print(secrets.token_hex(8))
PYOPAQUE
)"
REMOTE_IMAGE="ghcr.io/${OWNER,,}/omniedge-routeiq-track1:c-${OPAQUE}"
PUSH_LOG="$(mktemp)"

say "Publishing the perfect candidate under an opaque reference"
printf '%s' "$TOKEN" | docker login ghcr.io -u "$OWNER" --password-stdin >/dev/null 2>&1
docker tag "$LOCAL_IMAGE" "$REMOTE_IMAGE"
if ! docker push "$REMOTE_IMAGE" >"$PUSH_LOG" 2>&1; then
  tail -n 40 "$PUSH_LOG" >&2
  die "candidate push failed"
fi
DIGEST="$(grep -Eo 'sha256:[0-9a-f]{64}' "$PUSH_LOG" | tail -n1 || true)"

PRIVATE_FILE="/tmp/routeiq-v14-private-candidate.txt"
{
  printf 'PRIVATE — DO NOT POST IN DISCORD, README, OR SCREENSHOTS\n'
  printf 'image=%s\n' "$REMOTE_IMAGE"
  printf 'digest=%s\n' "$DIGEST"
  printf 'commit=%s\n' "$COMMIT"
  printf 'qwen_mode=%s\n' "$CHOSEN_MODE"
  printf 'benchmark_report=%s\n' "$REPORT"
  printf 'benchmark_results=%s\n' "$CHOSEN_ROOT/output/results.json"
  printf 'container_log=%s\n' "$CHOSEN_ROOT/container.log"
  printf 'push_log=%s\n' "$PUSH_LOG"
} > "$PRIVATE_FILE"
chmod 600 "$PRIVATE_FILE"

say "Verifying anonymous judge pull without exposing the candidate reference"
docker logout ghcr.io >/dev/null 2>&1 || true
docker image rm "$REMOTE_IMAGE" >/dev/null 2>&1 || true
if ! docker pull "$REMOTE_IMAGE" >/dev/null 2>&1; then
  die "published candidate cannot be pulled anonymously"
fi
PULLED_ARCH="$(docker image inspect --format '{{.Architecture}}' "$REMOTE_IMAGE")"
[[ "$PULLED_ARCH" == "amd64" ]] || die "published candidate is not linux/amd64"

say "V1.4 passed the perfect local gate and was published safely"
printf 'Private candidate details: %s\n' "$PRIVATE_FILE"
printf 'Benchmark report: %s\n' "$REPORT"
printf 'Selected local mode: %s\n' "$CHOSEN_MODE"
printf 'Source branch was NOT pushed. Portal submission was NOT changed.\n'
